INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Multi-format posting$q$, $q$Publish blog posts, short status updates, photos, bookmarks and other content types from a single composer.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Multi-author sites$q$, $q$Run a shared community or group site with an unlimited number of collaborators posting to one domain.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$POSSE syndication$q$, $q$Publish content on your own Known site first, then automatically push copies out to connected social networks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Bookmarklet$q$, $q$Save links and quickly post commentary on pages found anywhere else on the web.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Custom domains and styling$q$, $q$Attach your own domain and customize appearance with custom CSS and JavaScript.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Multiple feed formats$q$, $q$Expose site content as RSS, XML, JSON and KML feeds for interoperability with other tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Privacy controls$q$, $q$Run a fully public site, a private personal journal, or a closed group discussion space.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Self-hosted, open-source core$q$, $q$Install and run Known on your own PHP server for full data ownership with no platform lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Free and open source with no recurring platform fee$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Full data ownership since content lives on the operator's own domain and server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Supports both single-author blogs and multi-author community sites from one codebase$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Built on open IndieWeb standards for content portability and syndication$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Requires the user to find and manage their own PHP hosting and updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Slower development pace than commercial hosted platforms like WordPress.com or Ghost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Smaller plugin and theme ecosystem compared to mainstream CMS platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$No official managed hosted-plan option comparable to competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Is Known free to use$q$, $q$Yes, Known is free, open-source software. You install it on your own hosting, so the only cost is whatever web hosting you choose.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Who created Known$q$, $q$Known was co-founded by Ben Werdmuller and Erin Jo Richey and launched in 2014 after being incubated at the Matter Ventures accelerator in San Francisco.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$What is POSSE and how does Known use it$q$, $q$POSSE stands for Publish on your Own Site, Syndicate Elsewhere. Known lets you publish content to your own domain first and then automatically syndicate copies to connected social networks.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Can multiple people post to the same Known site$q$, $q$Yes, Known supports unlimited collaborators on a single site, making it suitable for community, classroom, or team publishing as well as personal blogging.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Does Known offer a hosted version$q$, $q$Known is primarily distributed as self-hosted open-source software; there is no widely advertised managed hosting tier comparable to WordPress.com.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$What content types can I publish with Known$q$, $q$Known supports blog posts, short status updates, photos, bookmarks, and other content types from a single posting interface.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Is Known part of the IndieWeb movement$q$, $q$Yes, Known follows IndieWeb principles around content ownership and portability, and its founder was previously involved in the open-source Elgg community platform.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Personal ownership-first blogging$q$, $q$Individuals who want to own their content and syndicate copies to social networks instead of posting natively into closed platforms.$q$, $q$Independent bloggers and IndieWeb enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Community and classroom publishing$q$, $q$Groups such as classrooms or research teams running a shared multi-author site under one domain.$q$, $q$Educators and community organizers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Media and journalism microsites$q$, $q$Small newsroom or media projects wanting a lightweight, self-hosted alternative to larger CMS platforms.$q$, $q$Independent journalists and media teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code","Unlimited self-hosted sites","Multi-author support","Community documentation"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$overview$q$, $q$What Is Known$q$, 2, ARRAY[$q$Known is an open-source social publishing engine built around the idea that individuals and groups should own their content rather than renting space on a closed social network. A single Known installation can serve as a personal blog or as a shared site for a whole community, with unlimited collaborators able to post to the same domain.$q$, $q$The project was co-founded by Ben Werdmuller and Erin Jo Richey and formally launched in 2014 after being incubated at the Matter Ventures media-startup program in San Francisco. Werdmuller's earlier work on the open-source platform Elgg fed directly into Known's design philosophy of decentralized, user-owned publishing.$q$, $q$Known follows the IndieWeb principle of publishing on your own site first and syndicating copies elsewhere (POSSE), rather than posting natively into a third-party platform's feed and losing control over that content.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$A single post in Known can be a blog article, a short status update, a photo, a bookmark, or another supported content type, all managed from one interface. A browser bookmarklet lets users quickly save or comment on pages they find elsewhere on the web.$q$, $q$Sites support custom domains, custom CSS and JavaScript, hashtag-based content organization, and both raw HTML and WYSIWYG editing. Output feeds are available in RSS, XML, JSON and KML so other tools and services can consume a site's content programmatically.$q$, $q$Because it is self-hosted, Known gives operators full control over privacy: a site can be fully public, a private single-author journal, or a closed group space for a defined set of collaborators.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Known is distributed as free, open-source software that a user downloads and installs on their own PHP hosting, so there is no vendor subscription fee for the software itself -- the only ongoing cost is whatever web hosting the operator chooses.$q$, $q$There is no current tiered commercial hosted plan comparable to WordPress.com; anyone who wants a managed Known site is generally expected to install it on standard shared or cloud PHP hosting themselves or work with a developer to do so.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ece3f5b6-3302-4069-a41e-b5e480349b71', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Drag-and-drop editor$q$, $q$Design pixel-precise pages visually without writing code, using the classic Wix Editor or the agency-oriented Wix Studio.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$AI site generation$q$, $q$Generate a starting website design, layout and copy from a short description of your business.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Wix Stores ecommerce$q$, $q$Sell products online with product catalogs, cart, checkout, inventory and payment processing built in.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Wix Bookings$q$, $q$Manage appointments, staff calendars and service payments for service-based businesses.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$App Market integrations$q$, $q$Extend site functionality with hundreds of first-party and third-party apps covering marketing, forms, chat and more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Velo custom development$q$, $q$Build custom logic, databases and API-driven functionality on top of a Wix site using a full code environment.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Built-in SEO tools$q$, $q$Manage meta tags, structured data, sitemaps and mobile optimization from a dedicated SEO dashboard.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Hosting and security included$q$, $q$Every paid plan bundles managed hosting, SSL, and infrastructure so there is no separate hosting provider to manage.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$All-in-one platform bundles hosting, design, ecommerce and marketing in one subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Beginner-friendly drag-and-drop editor with a large template library$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$AI-assisted site generation speeds up initial setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Broad app marketplace and Velo development environment support advanced customization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Publicly traded, well-resourced company with continuous product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Sites cannot be exported or migrated off the Wix platform to another host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Ecommerce features require at least the Core paid plan, unlike some competitors' free tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Costs can climb quickly once premium apps and higher-volume ecommerce tiers are added$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Design flexibility on the classic Editor can be more rigid than fully custom-coded sites at scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$How much does Wix cost$q$, $q$Wix's four paid plans for 2026 are Light at $17/month, Core at $29/month, Business at $39/month and Business Elite at $159/month on annual billing, plus a limited free plan with Wix branding and no ecommerce.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Can I sell products with the free Wix plan$q$, $q$No. Ecommerce and payment processing require at least the Core plan; the free and Light tiers do not support product listings or checkout.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Who founded Wix$q$, $q$Wix was founded in 2006 in Tel Aviv, Israel by Avishai Abrahami, Nadav Abrahami and Giora Kaplan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Is Wix publicly traded$q$, $q$Yes, Wix.com Ltd. has traded on the NASDAQ under the ticker WIX since its IPO in November 2013.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Can I move my Wix site to another host$q$, $q$No, Wix does not support exporting a site to run it on external hosting; the site remains tied to the Wix platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$What is Wix Studio$q$, $q$Wix Studio is a more structured, agency-oriented editor built for freelancers and agencies managing multiple client sites, offering reusable design assets and collaboration tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Does Wix support custom code$q$, $q$Yes, through Velo, Wix's built-in development environment, which allows JavaScript-based custom logic, databases and API integrations.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$What is Wix best for$q$, $q$Wix is best suited for small businesses, freelancers, and agencies that want an all-in-one, code-free way to launch a professional website, store or booking system quickly.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Small business website and store$q$, $q$Launch a professional site with an online store, bookings and payments without hiring a developer.$q$, $q$Small business owners and solopreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Agency client site production$q$, $q$Design and manage multiple client websites efficiently using Wix Studio's reusable assets and collaboration tools.$q$, $q$Design agencies and freelance web designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Service-business scheduling$q$, $q$Run appointment booking, staff calendars and service payments for salons, consultants and other service providers.$q$, $q$Service-based businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Wix-branded domain","Wix ads displayed","Basic templates","No ecommerce"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Light$q$, $q$$17/month$q$, $q$annual$q$, NULL, $q$["Connect a custom domain","No Wix ads","Basic site analytics","No ecommerce"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Core$q$, $q$$29/month$q$, $q$annual$q$, NULL, $q$["Ecommerce and payments enabled","Wix Payments support","Basic marketing tools","Site analytics"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Business$q$, $q$$39/month$q$, $q$annual$q$, NULL, $q$["Advanced ecommerce features","Higher storage and bandwidth","Automations","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$Business Elite$q$, $q$$159/month$q$, $q$annual$q$, NULL, $q$["Highest resource limits","Advanced ecommerce and reporting","Dedicated support","Enterprise-grade features"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$overview$q$, $q$What Is Wix$q$, 2, ARRAY[$q$Wix is an all-in-one website building and business platform that combines hosting, design tools, ecommerce, marketing and customer-management features into a single cloud-based product. It is aimed at solo entrepreneurs, freelancers, agencies and small-to-midsize businesses that want to launch a professional site without hiring a developer.$q$, $q$Founded in 2006 in Tel Aviv by Avishai Abrahami, Nadav Abrahami and Giora Kaplan, Wix has grown into a publicly traded company on the NASDAQ (WIX) with offices across multiple continents. Its product line has expanded well beyond the original drag-and-drop editor to include dedicated tools for online stores, bookings, restaurants, and enterprise-grade custom development through Velo.$q$, $q$Wix's core differentiator is breadth: rather than stitching together separate hosting, CMS, ecommerce and email-marketing vendors, users get all of it bundled into one subscription and one dashboard.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Wix Editor provides pixel-precise drag-and-drop page building, while Wix Studio offers a more structured, agency-oriented workflow with reusable design assets and client-handoff tools. Wix's AI site generator can produce a starting layout, copy, and images from a short text description of the business.$q$, $q$Wix Stores adds product catalogs, cart and checkout, inventory management and integration with Wix Payments and third-party processors, while Wix Bookings handles appointment scheduling, staff calendars and service payments for service-based businesses.$q$, $q$The Wix App Market extends functionality with hundreds of third-party and first-party integrations, and Velo provides a full JavaScript-based development environment for building custom logic, databases and API integrations on top of a Wix site.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wix offers a free plan with Wix branding, ads, and no ecommerce capability, aimed at trying the editor before committing. In 2025 Wix consolidated its paid tiers into four simplified plans for 2026: Light at $17/month, Core at $29/month, Business at $39/month, and Business Elite at $159/month, all priced on annual billing (monthly billing is somewhat higher for each tier).$q$, $q$Selling products online requires at least the Core plan, since the free and Light tiers exclude checkout and payment processing. Business and Business Elite add higher-volume ecommerce features, advanced automations, and priority support aimed at growing stores.$q$, $q$Additional costs can include premium apps from the Wix App Market, a custom domain if not already owned, and Wix Payments transaction fees on ecommerce sales.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2a6940b9-4b57-4612-8541-84535793b340', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Agentless cloud scanning$q$, $q$Connects via cloud provider APIs to build a full inventory and risk graph without deploying agents on every workload.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Attack-path analysis$q$, $q$Correlates misconfigurations, vulnerabilities, identity risk and exposure to surface exploitable attack chains, not just isolated findings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Multi-cloud coverage$q$, $q$Supports AWS, Microsoft Azure, Google Cloud Platform, Oracle Cloud Infrastructure and Kubernetes environments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$CSPM and CWPP in one platform$q$, $q$Combines cloud security posture management and workload protection so teams do not need separate point tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Data security posture management$q$, $q$Identifies where sensitive data lives across cloud storage and databases and flags exposure risk.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Cloud identity and entitlement management$q$, $q$Analyzes IAM roles and permissions to find excessive or risky entitlements across cloud accounts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Kubernetes security posture management$q$, $q$Assesses container and Kubernetes configurations for misconfigurations and runtime risk.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Risk prioritization dashboard$q$, $q$Ranks findings by real-world exploitability so security teams can focus remediation on what matters most.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Unifies multiple previously separate cloud security tool categories into one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Agentless deployment enables fast, broad environment coverage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Attack-path analysis reduces alert fatigue by prioritizing real, chained risk$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Backed by Google Cloud's scale and resources following the 2025-2026 acquisition$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Enterprise, custom pricing with no published self-serve tiers makes cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Primarily built for larger organizations with meaningful multi-cloud footprints, less suited to very small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Now owned by Google Cloud, which may raise vendor-neutrality questions for customers on competing clouds$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Full platform value typically requires licensing multiple modules, which can add complexity to procurement$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$What does Wiz do$q$, $q$Wiz is a cloud-native application protection platform that scans cloud and Kubernetes environments to find, correlate and prioritize security risks such as misconfigurations, vulnerabilities, exposed secrets and identity risk.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Who founded Wiz$q$, $q$Wiz was founded in January 2020 by Assaf Rappaport, Yinon Costica, Roy Reznik and Ami Luttwak, who had previously founded and sold the cloud security company Adallom to Microsoft.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Is Wiz the same as Wix$q$, $q$No. Wiz (wiz.io) is a cloud security company for enterprises; Wix (wix.com) is an unrelated consumer and small-business website builder. The similar names are coincidental.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Did Google acquire Wiz$q$, $q$Yes, Google announced an all-cash agreement to acquire Wiz for approximately 32 billion dollars in March 2025, and the deal closed with Wiz joining Google Cloud, making it the largest cybersecurity acquisition on record.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Does Wiz only work with Google Cloud$q$, $q$No, Wiz continues to support multiple cloud providers including AWS, Microsoft Azure, Google Cloud and Oracle Cloud Infrastructure even after becoming part of Google Cloud.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$How is Wiz priced$q$, $q$Wiz uses custom, sales-led enterprise pricing rather than published self-serve plans, typically scoped to cloud workload volume and which security modules are licensed.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$What is a CNAPP$q$, $q$A cloud-native application protection platform (CNAPP) is a unified security tool category, popularized in large part by Wiz, that combines posture management, workload protection, identity risk and data security into one platform.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Who are Wiz's main competitors$q$, $q$Wiz competes with cloud security vendors such as Palo Alto Networks (Prisma Cloud), Orca Security, CrowdStrike, Microsoft Defender for Cloud, and Aqua Security.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Multi-cloud risk visibility$q$, $q$Give security teams a single, prioritized view of risk across AWS, Azure, Google Cloud and Oracle Cloud accounts.$q$, $q$Enterprise cloud security and DevSecOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Kubernetes and container security$q$, $q$Identify misconfigurations and runtime risk in containerized workloads before they reach production.$q$, $q$Platform engineering and Kubernetes operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Compliance and audit readiness$q$, $q$Continuously assess cloud configurations against compliance frameworks to prepare for audits.$q$, $q$Compliance officers and CISOs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$Enterprise (custom)$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Scoped to cloud workload and account volume","Modular licensing across CSPM, CWPP, DSPM, CIEM and Kubernetes security","Dedicated sales and onboarding support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$overview$q$, $q$What Is Wiz$q$, 2, ARRAY[$q$Wiz is a cloud-native application protection platform built to give security teams a unified, prioritized view of risk across multi-cloud and Kubernetes environments. It connects agentlessly to a customer's cloud accounts and constructs a graph of the entire environment, correlating vulnerabilities, misconfigurations, identity risk, exposed secrets and network exposure to surface the attack paths that actually matter.$q$, $q$The company was founded in January 2020 by Assaf Rappaport, Yinon Costica, Roy Reznik and Ami Luttwak, the same team that previously built and sold cloud security company Adallom to Microsoft. Wiz is headquartered in New York City and grew into one of the fastest-scaling cybersecurity companies of the 2020s.$q$, $q$In March 2025 Google announced it would acquire Wiz for approximately 32 billion dollars in an all-cash deal, the largest cybersecurity acquisition on record; the deal closed and Wiz joined Google Cloud in 2026 while continuing to support other major clouds.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wiz's platform combines cloud security posture management (CSPM), cloud workload protection (CWPP), Kubernetes security posture management (KSPM), data security posture management (DSPM) and cloud infrastructure entitlement management (CIEM) into a single product, replacing what previously required multiple point tools.$q$, $q$Its signature capability is attack-path analysis: mapping how a combination of individually minor issues, such as an exposed secret plus an overly permissive role plus a public-facing workload, could chain together into a critical breach path, then ranking findings by real exploitability rather than raw vulnerability counts.$q$, $q$Because Wiz connects via cloud provider APIs rather than requiring agents on every host, it can achieve full environment coverage quickly during onboarding, which has been a major driver of its enterprise adoption speed.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wiz does not publish self-serve pricing; it is sold to enterprises through a custom, sales-led process, with cost generally scoped to the number of cloud workloads, accounts, and which modules (CSPM, CWPP, DSPM, CIEM, container/Kubernetes security) a customer licenses.$q$, $q$Prospective customers typically engage Wiz's sales team for a scoped demo and quote rather than signing up through a published pricing page, which is standard practice for platform-scale enterprise cloud security tools.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$LinkedIn Sales Navigator export$q$, $q$Export search results directly from LinkedIn Sales Navigator into a verified contact list.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Real-time email verification$q$, $q$Verifies each business email address for deliverability at the moment of export to reduce bounce rates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Mobile phone number lookup$q$, $q$Reveals verified mobile numbers for contacts on higher-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Chrome extension$q$, $q$Runs directly inside the LinkedIn and Sales Navigator interface for one-click list building.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$CRM integrations$q$, $q$Pushes exported contacts directly into common CRM and sales-engagement platforms.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$AI-assisted research$q$, $q$Surfaces additional context on prospects to support personalized outreach.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$API access$q$, $q$Programmatic access to search and enrichment on the Team plan for custom workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$CSV import and export$q$, $q$Bulk import existing lists for enrichment or export verified results for use elsewhere.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Deep, purpose-built integration with LinkedIn Sales Navigator search$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Real-time email verification helps keep bounce rates low$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Free plan and pay-as-you-go pricing let small users try the product with no subscription$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Large claimed contact database and CRM integrations support end-to-end outbound workflows$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Reliant on LinkedIn's platform and search limits, which can affect volume and consistency$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Costs scale quickly for teams needing unlimited reveals across multiple seats$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Team plan requires a minimum of three users and annual billing, limiting flexibility for small teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Data accuracy on phone numbers can vary more than on email addresses, as with most contact-data providers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$What does Wiza do$q$, $q$Wiza turns LinkedIn and LinkedIn Sales Navigator search results into verified email addresses and phone numbers that can be exported for sales, recruiting or marketing outreach.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$How much does Wiza cost$q$, $q$Wiza has a free plan, a Starter plan at 49 dollars per month per user, an Email plan at 83 dollars per month, an Email plus Phone plan at 166 dollars per month, and a custom-priced Team plan requiring three or more users.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Does Wiza verify emails in real time$q$, $q$Yes, Wiza verifies each email address for deliverability at the moment it is exported rather than relying solely on a static pre-built database.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Is Wiza the same company as Wix or Wiz$q$, $q$No. Wiza is an unrelated LinkedIn prospecting tool; Wix is a website builder and Wiz is a cloud security company. The similar names are coincidental.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$When was Wiza founded$q$, $q$Wiza was founded in 2019.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Can I use Wiza without a subscription$q$, $q$Yes, Wiza offers pay-as-you-go pricing at roughly 35 cents per verified email and 1.50 dollars per verified phone number for users who do not want a recurring plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Does Wiza integrate with CRMs$q$, $q$Yes, Wiza offers native CRM and sales-engagement integrations so exported contacts can flow directly into an existing sales pipeline.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Outbound sales prospecting$q$, $q$Build verified lead lists from LinkedIn Sales Navigator searches for cold email and outreach campaigns.$q$, $q$SDRs and outbound sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Recruiting candidate sourcing$q$, $q$Find verified contact details for candidates identified through LinkedIn searches.$q$, $q$Recruiters and talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Marketing list building$q$, $q$Generate targeted, verified contact lists for account-based marketing campaigns.$q$, $q$B2B marketers and demand generation teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["20 valid emails","5 phone numbers"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Starter$q$, $q$$49/month per user$q$, $q$monthly$q$, NULL, $q$["100 valid emails per month","100 phone numbers per month","Team analytics","CRM integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Email$q$, $q$$83/month ($990/year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited email reveals","2,500 exports per month","AI research","CRM integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Email + Phone$q$, $q$$166/month ($1,990/year annual)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited email and phone reveals","2,500 exports per month","AI research","CRM integrations"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$Team$q$, $q$Custom pricing$q$, $q$annual$q$, NULL, $q$["Minimum 3 users","Unlimited emails and phone numbers","API access","Dedicated success manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$overview$q$, $q$What Is Wiza$q$, 2, ARRAY[$q$Wiza is a prospecting tool purpose-built around LinkedIn and LinkedIn Sales Navigator. Instead of building a general contact database from scratch, it lets sales, recruiting and marketing users run a search directly inside LinkedIn or Sales Navigator, then export the matching profiles through Wiza, which looks up and verifies a business email address (and, on higher plans, a mobile number) for each contact before the list downloads.$q$, $q$Founded in 2019, Wiza has grown into a widely used LinkedIn-to-email tool, claiming access to a database of more than 850 million contacts and use by over 500,000 go-to-market professionals across sales, recruiting and marketing teams.$q$, $q$The product ships as both a web application and a Chrome browser extension that overlays directly on LinkedIn and Sales Navigator search results, so users can trigger an export without leaving LinkedIn's own interface.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wiza's central feature is real-time email verification: rather than pulling from a static, potentially stale database, it verifies deliverability at the moment of export, which is intended to reduce bounce rates in outbound campaigns.$q$, $q$Beyond email, higher-tier plans add mobile phone number lookups, AI-assisted research on prospects, and advanced contact fields such as job history and company firmographic data.$q$, $q$Native CRM and sales-engagement integrations, API access on the Team plan, and CSV import/export let exported lists flow directly into a seller's or recruiter's existing pipeline without manual re-entry.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5118dfca-71e6-4897-bbc7-33e7b849b457', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wiza offers a free plan with a small allotment of verified emails and phone numbers, a Starter plan at 49 dollars per month per user, and two higher self-serve tiers at 83 dollars per month for unlimited email reveals and 166 dollars per month for unlimited email and phone reveals, each also available at a discount on annual billing.$q$, $q$A custom-priced Team plan requires a minimum of three users, billed annually, and adds unlimited reveals for the whole team, API access, CSV import, advanced fields, and a dedicated success manager.$q$, $q$For occasional use without a subscription, Wiza also offers pay-as-you-go pricing at roughly 35 cents per verified email and 1.50 dollars per verified phone number.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Five-file architecture$q$, $q$The entire CMS is contained in just five files, with no database server required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$JSON flat-file database$q$, $q$Stores content in a simple JSON text file instead of MySQL or another relational database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$One-click installs, updates and backups$q$, $q$Install by uploading files, then manage updates and backups from the admin panel with a single click.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Built-in theme and plugin installer$q$, $q$Browse and install themes and plugins directly from the admin dashboard.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Per-page SEO fields$q$, $q$Set a custom title, meta keywords and meta description for each page without a separate SEO plugin.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Security hardening$q$, $q$Includes HTTPS support, hashed admin passwords, CSRF protection, and a customizable admin login URL.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Privacy by default$q$, $q$Ships with no ads, no tracking scripts, and no powered-by links, and is GDPR compliant out of the box.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$High page-speed scores$q$, $q$Default installs commonly score 100 out of 100 on PageSpeed tests due to the lack of database overhead.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Completely free and open source under the permissive MIT license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Extremely lightweight with no database server to install or maintain$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Fast default page-load performance thanks to the flat-file architecture$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Simple, minimal codebase that is easy to audit and self-host$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Privacy-respecting by default with no ads or tracking$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Much smaller plugin and theme ecosystem than WordPress or other mainstream CMS platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Not designed for complex content structures, ecommerce, or high-traffic multi-author sites$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Flat-file storage can become harder to manage at very large content volumes compared to a database$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Smaller community means fewer tutorials and third-party resources than larger CMS platforms$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Is WonderCMS free$q$, $q$Yes, WonderCMS is free and open source under the MIT license, with no paid tier or subscription fee for the software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Does WonderCMS need a database$q$, $q$No, WonderCMS stores its content in a JSON flat file instead of a relational database like MySQL, so no database server is required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$How do I install WonderCMS$q$, $q$Installation is a one-step process: unzip and upload the five WonderCMS files to any PHP-capable web host, then configure the site through the browser-based admin panel.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Is WonderCMS good for large websites$q$, $q$WonderCMS is best suited for small, simple sites such as landing pages, portfolios and brochure sites; it is not designed for complex, high-traffic or ecommerce-heavy websites.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Does WonderCMS support plugins and themes$q$, $q$Yes, WonderCMS includes a built-in theme and plugin installer accessible directly from the admin dashboard.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Is WonderCMS secure$q$, $q$WonderCMS includes HTTPS support, hashed admin passwords, CSRF protection, single-cookie sessions and a customizable login URL as standard security measures.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$How long has WonderCMS existed$q$, $q$WonderCMS has been developed since 2008 as a free, open-source flat-file CMS project.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Lightweight landing pages$q$, $q$Launch a fast-loading landing or brochure site without setting up a database.$q$, $q$Freelancers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Developer portfolios$q$, $q$Run a simple, easily auditable personal or portfolio site with minimal maintenance overhead.$q$, $q$Independent developers and designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Low-resource hosting environments$q$, $q$Deploy a CMS on very inexpensive or resource-constrained hosting where a database server is impractical.$q$, $q$Budget-conscious site owners and hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code","Unlimited self-hosted installs","Theme and plugin installer","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$overview$q$, $q$What Is WonderCMS$q$, 2, ARRAY[$q$WonderCMS is a flat-file content management system built around extreme simplicity: the whole application is five files, and it stores content in a JSON text file rather than a relational database, so there is nothing to install or configure beyond uploading files to PHP hosting.$q$, $q$The project has been developed since 2008 and is released as free, open-source software under the MIT license, which permits commercial use, modification and redistribution with attribution.$q$, $q$It is aimed at developers, freelancers and small businesses who want to launch a simple site -- a landing page, brochure site, portfolio or small blog -- without the database dependency, plugin sprawl, or maintenance overhead of larger CMS platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Installation is a one-step process: unzip and upload five files, then configure the site through a browser-based admin panel. There is no database server to set up and no connection string to manage.$q$, $q$The admin panel includes a theme and plugin installer, one-click backups, one-click updates, a built-in file manager, clean and customizable URLs, a configurable homepage, and a customizable admin login URL for added security.$q$, $q$Because there is no database query overhead, default installations commonly score 100 out of 100 on PageSpeed tests for both desktop and mobile, and the platform includes built-in per-page SEO fields for title, meta keywords and meta description.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WonderCMS is completely free and open source under the MIT license; there is no paid tier, subscription, or licensing fee for the software itself.$q$, $q$The only cost to run a WonderCMS site is standard PHP-capable web hosting, which can be very inexpensive given the platform's minimal file size and lack of database requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d7da54f6-2b64-440b-9f41-a831adbd9e11', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Free open-source core plugin$q$, $q$Add full ecommerce functionality to WordPress at no licensing cost, with unlimited products and orders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WooPayments and 100+ gateways$q$, $q$Accept credit cards, digital wallets and bank transfers through WooPayments or over 100 supported third-party gateways.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Shipping and label printing$q$, $q$Print USPS shipping labels directly from the dashboard and connect with carriers like UPS and FedEx.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Extension marketplace$q$, $q$Add subscriptions, bookings, memberships and advanced shipping rules through paid and free extensions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Full REST API$q$, $q$Build custom integrations and headless storefronts on top of WooCommerce's complete API.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WordPress content integration$q$, $q$Combine rich blog and landing-page content with ecommerce on the same WordPress site.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Tax calculation tools$q$, $q$Automatically calculate applicable sales tax across regions using built-in and extension-based tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Large theme ecosystem$q$, $q$Choose from thousands of WordPress themes to fully customize a store's design.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Core plugin is completely free with no revenue share on sales$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Full ownership of code, data and hosting since it runs on the merchant's own WordPress site$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Combines WordPress's content-management strength with full ecommerce functionality$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Massive extension and theme ecosystem for deep customization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Backed by Automattic, a large and well-resourced company, since 2015$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Requires managing your own WordPress hosting, updates and plugin compatibility$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Paid extensions can add up quickly, offsetting the free core plugin's cost advantage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$More technical setup and maintenance burden than fully hosted platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Performance and security depend heavily on hosting quality and plugin choices$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Is WooCommerce free$q$, $q$Yes, the core WooCommerce plugin is free and open source with no platform fee or revenue share; costs come from hosting, domains and optional paid extensions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Who owns WooCommerce$q$, $q$WooCommerce is owned by Automattic, the company behind WordPress.com and Jetpack, which acquired the plugin's creator WooThemes in May 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$When was WooCommerce launched$q$, $q$WooCommerce launched publicly on September 27, 2011, developed by WooThemes as a fork of the earlier Jigoshop plugin.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Do I need WordPress to use WooCommerce$q$, $q$Yes, WooCommerce is a WordPress plugin and requires an existing WordPress installation to run.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$How does WooCommerce compare to Shopify$q$, $q$WooCommerce is a free, self-hosted plugin giving full control over code and hosting with no revenue share, while Shopify is a fully hosted platform with monthly fees and, on some plans, transaction fees, but less setup and maintenance responsibility.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$What payment gateways does WooCommerce support$q$, $q$WooCommerce supports WooPayments, its native gateway, along with more than 100 third-party payment gateways including Stripe, PayPal and Square.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Are WooCommerce extensions required$q$, $q$No, the free core plugin includes unlimited products, orders and a full API; extensions are optional and add specific functionality like subscriptions or advanced shipping.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Is WooCommerce suitable for large stores$q$, $q$Yes, WooCommerce can scale to large catalogs and high traffic with proper hosting, caching and performance optimization, and is used by stores of many sizes.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Content-driven ecommerce$q$, $q$Combine blog content, SEO landing pages and an online store on a single WordPress site.$q$, $q$Content marketers and bloggers adding a store$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Custom-built online stores$q$, $q$Build a fully customized store with specific extensions, themes and integrations not available on closed hosted platforms.$q$, $q$Developers and agencies building bespoke ecommerce sites$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Small to midsize retail businesses$q$, $q$Launch a self-hosted online store without recurring platform fees or revenue share on sales.$q$, $q$Small and midsize retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Core Plugin$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Unlimited products and orders","Full REST API","WooPayments support","Tax calculation tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Paid Extensions$q$, $q$$29-$299/year per extension$q$, $q$annual$q$, NULL, $q$["Subscriptions and memberships","Advanced shipping rules","Specialized payment gateways","Marketing and merchandising tools"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$overview$q$, $q$What Is WooCommerce$q$, 2, ARRAY[$q$WooCommerce is a free, open-source plugin that adds full ecommerce functionality -- product catalogs, cart, checkout, payments, shipping and order management -- to any WordPress website, making it one of the most widely used ecommerce platforms on the web by installation count.$q$, $q$The plugin originated with WooThemes, a WordPress theme shop founded in 2008, and launched publicly on September 27, 2011, as a fork of the earlier Jigoshop plugin. It grew rapidly, reaching 1 million downloads by 2013, and in May 2015 was acquired by Automattic, the company behind WordPress.com and Jetpack, for a reported 30 million dollars.$q$, $q$Because WooCommerce is a plugin rather than a hosted SaaS product, store owners run it on their own WordPress installation and hosting, giving them full control over their store's code, data and infrastructure, in contrast to closed hosted platforms like Shopify.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free core plugin supports unlimited products and orders, a full REST API for custom integrations, and built-in tools for tax calculation and shipping label printing, including direct USPS label printing and carrier integrations with UPS and FedEx.$q$, $q$Payments can be processed through WooPayments, Automattic's native payment gateway, or through more than 100 supported third-party gateways such as Stripe, PayPal and Square, giving merchants flexibility in how they accept credit cards, digital wallets and bank transfers.$q$, $q$A large marketplace of official and third-party extensions adds functionality such as subscriptions, bookings, memberships, advanced shipping rules and marketing tools, letting merchants build a store that matches their exact needs rather than accepting a fixed feature set.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The WooCommerce plugin itself is free and open source, with no platform fee or revenue share on sales, unlike hosted ecommerce platforms that charge a percentage of transactions.$q$, $q$Store owners instead pay for hosting (commonly 25 to 350 dollars per month depending on traffic and performance needs), a domain name, and any optional paid extensions, which typically cost 29 to 299 dollars per year each.$q$, $q$Payment processing fees apply per transaction through WooPayments or whichever third-party gateway a merchant chooses, similar to standard card-processing fees across the industry.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Multi-step cold email campaigns$q$, $q$Build sequenced email campaigns with automated follow-ups based on prospect behavior.$q$, 0);
