INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Prospecting and list building$q$, $q$Find and enrich prospect contact data before launching outbound campaigns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$CRM and sales-tool integrations$q$, $q$Sync replies, opens and campaign activity with common CRMs and sales-engagement tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Contacted-prospects pricing model$q$, $q$Pay based on how many new prospects are added to campaigns rather than a flat per-seat fee.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Reply detection and follow-up automation$q$, $q$Automatically pause or branch sequences when a prospect replies.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Team collaboration and reporting$q$, $q$Manage multiple senders and campaigns with shared visibility into outbound performance.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Combines cold email and LinkedIn outreach in one workflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Deliverability-focused tooling helps protect sender reputation$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Flexible contacted-prospects pricing scales with actual usage$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$14-day free trial or 100 free emails let teams evaluate before paying$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Publicly traded company with an established track record since 2015$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$LinkedIn automation and some integrations cost extra on top of the base plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Contacted-prospects pricing can become harder to predict for teams with variable outbound volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Lighter feature set than large enterprise sales-engagement suites like Outreach or Salesloft$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Primarily focused on outbound email and LinkedIn, not a full CRM replacement$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$What does Woodpecker do$q$, $q$Woodpecker is a cold email and LinkedIn outreach platform that helps sales teams run multi-step outbound campaigns with prospecting, follow-ups and deliverability tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$How much does Woodpecker cost$q$, $q$Woodpecker's base cold email plan starts around 29 dollars per month using a contacted-prospects pricing model, with LinkedIn automation at an additional 29 dollars per month per account and some integrations costing 20 dollars extra.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Is there a free trial for Woodpecker$q$, $q$Yes, Woodpecker offers a 14-day free trial or a cap of 100 free cold emails for new users.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Where is Woodpecker based$q$, $q$Woodpecker was founded in 2015 and is headquartered in Wroclaw, Poland.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Is Woodpecker publicly traded$q$, $q$Yes, Woodpecker is listed on the Warsaw Stock Exchange under the ticker WPR.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Is Woodpecker the same as Woodpecker CI$q$, $q$No, Woodpecker (woodpecker.co) is a cold email and LinkedIn outreach SaaS tool, while Woodpecker CI (woodpecker-ci.org) is an unrelated open-source continuous integration platform. They share a name but are entirely different products.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Does Woodpecker support LinkedIn outreach$q$, $q$Yes, Woodpecker lets users add LinkedIn touchpoints as steps within a multi-channel outbound campaign, priced as an add-on per connected LinkedIn account.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$What is the contacted-prospects pricing model$q$, $q$Instead of charging a flat per-seat fee, Woodpecker prices plans based on how many new prospects a customer adds to campaigns during a billing cycle.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Outbound sales pipeline generation$q$, $q$Run multi-step cold email and LinkedIn campaigns to book meetings with target prospects.$q$, $q$SDRs and outbound sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Agency outbound campaigns for clients$q$, $q$Manage outbound cold email and LinkedIn outreach on behalf of multiple client accounts.$q$, $q$Lead generation and outbound marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Founder-led sales outreach$q$, $q$Run early-stage outbound campaigns without a dedicated SDR team.$q$, $q$Startup founders and small business owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$Cold Email$q$, $q$From $29/month$q$, $q$monthly$q$, NULL, $q$["Contacted-prospects pricing","Multi-step email sequences","Deliverability tools","CRM integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$LinkedIn Add-on$q$, $q$$29/month per LinkedIn account$q$, $q$monthly$q$, NULL, $q$["LinkedIn outreach steps","Combined email plus LinkedIn sequences"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$overview$q$, $q$What Is Woodpecker$q$, 2, ARRAY[$q$Woodpecker is a cold email and LinkedIn outreach platform built for businesses that rely on outbound prospecting to generate sales pipeline. It brings prospecting, multi-step email sequencing, LinkedIn outreach steps, automated follow-ups and deliverability tools together into a single outbound workflow.$q$, $q$Founded in 2015 in Wroclaw, Poland, Woodpecker has grown into a publicly traded company on the Warsaw Stock Exchange (ticker WPR), with roughly 90 employees and more than 15,000 users spanning over 100 countries.$q$, $q$The platform is positioned around deliverability and reply quality rather than raw send volume, aiming to keep cold outreach out of spam folders while helping sales teams and agencies book more qualified meetings.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Woodpecker supports multi-step, multi-channel campaigns that combine cold email sequences with LinkedIn touchpoints, automated follow-ups triggered by prospect behavior, and built-in deliverability safeguards such as email warm-up and sending pattern controls.$q$, $q$Prospecting tools help users build and enrich contact lists before launching a campaign, while native integrations sync replies, opens and campaign activity with common CRMs and sales tools.$q$, $q$A dedicated deliverability dashboard gives visibility into inbox placement, bounce rates and sender reputation so teams can adjust sending behavior before problems affect an entire domain's email reputation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9716dcf4-3238-4e9c-b8bc-c5a16aa3e250', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Woodpecker prices its core cold email plan around a 'contacted prospects' model, starting at roughly 29 dollars per month for a base number of prospects contacted per billing cycle and increasing as that ceiling rises.$q$, $q$LinkedIn automation is billed separately at 29 dollars per month per connected LinkedIn account, and certain integrations carry an additional 20 dollar charge, letting customers add channels and tools incrementally rather than paying for a fixed all-in-one bundle.$q$, $q$New users can start with a 14-day free trial or a limit of 100 free cold emails before choosing a paid plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Docker-based pipeline execution$q$, $q$Runs each pipeline step inside its own Docker container for isolated, reproducible builds.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Drone-compatible YAML syntax$q$, $q$Supports Drone's existing pipeline configuration format for easy migration from Drone CI.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Modernized web UI$q$, $q$Provides an updated interface for managing pipelines, builds and logs compared to legacy Drone.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Trusted pipeline steps$q$, $q$Allows controlled, privileged access for specific pipeline steps that need elevated permissions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Plugin marketplace$q$, $q$Extend pipeline functionality with community and official plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Git host integrations$q$, $q$Connects with GitHub, GitLab, Gitea, Bitbucket and other Git hosting platforms to trigger builds.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Conditional pipeline execution$q$, $q$Run or skip pipeline steps based on branch, event type or other build conditions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Apache 2.0 open-source license$q$, $q$Free to use, modify and self-host, with a stated commitment to remain open source permanently.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Completely free and open source under the permissive Apache 2.0 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Drone-compatible pipeline syntax makes migration from Drone straightforward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Community-driven governance avoids the vendor license changes that motivated the original fork$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Docker-based execution gives isolated, reproducible build environments$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$No per-seat or per-build fees since it is self-hosted$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Requires self-hosting and infrastructure management, unlike fully managed CI/CD SaaS products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Smaller contributor base and ecosystem than major hosted platforms like GitHub Actions or CircleCI$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Community-run project may have less predictable release cadence than a commercially backed product$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Documentation and enterprise support options are more limited than commercial CI/CD vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Is Woodpecker CI free$q$, $q$Yes, Woodpecker CI is completely free and open source under the Apache 2.0 license, with no paid tier required.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Is Woodpecker CI a fork of Drone$q$, $q$Yes, Woodpecker CI was forked from Drone CI in 2019 after Drone's license changed from Apache 2.0 to a proprietary license, to preserve a genuinely free and open-source CI/CD option.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Can I migrate from Drone to Woodpecker CI$q$, $q$Yes, Woodpecker maintains backward compatibility with Drone's YAML pipeline syntax, so existing Drone pipeline configuration files typically work with minimal changes.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Does Woodpecker CI use Docker$q$, $q$Yes, Woodpecker executes each pipeline step inside its own Docker container, giving builds isolated and reproducible environments.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$What Git platforms does Woodpecker CI support$q$, $q$Woodpecker integrates with GitHub, GitLab, Gitea, Bitbucket and other common Git hosting platforms to trigger pipelines on code changes.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Is Woodpecker CI the same as Woodpecker the sales tool$q$, $q$No, Woodpecker CI (woodpecker-ci.org) is an unrelated open-source CI/CD platform; Woodpecker (woodpecker.co) is a separate cold email and LinkedIn outreach SaaS product. They share a name coincidentally.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Who maintains Woodpecker CI$q$, $q$Woodpecker CI is maintained by a community of open-source contributors under the woodpecker-ci GitHub organization rather than a single commercial vendor.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$When was Woodpecker CI first released$q$, $q$The first release under the Woodpecker name, version 0.8.104, was published on September 9, 2019.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Self-hosted CI/CD for open-source projects$q$, $q$Run build, test and deployment pipelines without relying on a hosted SaaS CI provider.$q$, $q$Open-source maintainers and independent developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Migrating away from commercially licensed Drone$q$, $q$Replace a Drone CI installation with a fully free, community-governed alternative using compatible pipeline syntax.$q$, $q$Teams previously on Drone CI$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Cost-conscious internal CI/CD infrastructure$q$, $q$Run continuous integration and delivery pipelines on owned infrastructure to avoid per-seat or per-build SaaS fees.$q$, $q$Engineering teams managing their own infrastructure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$Open Source (self-hosted)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Full source code under Apache 2.0","Unlimited self-hosted pipelines","Docker-based execution","Community plugin marketplace"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$overview$q$, $q$What Is Woodpecker CI$q$, 2, ARRAY[$q$Woodpecker CI is a free, open-source continuous integration and delivery engine that executes pipeline steps inside Docker containers, giving each build step an isolated and reproducible environment.$q$, $q$The project began in 2019 as a community fork of Drone CI, created after Drone's license changed from Apache 2.0 to a proprietary license following its 0.8 release. Developer laszlocph forked the last Apache-licensed Drone codebase to preserve a genuinely free path for users, and the first Woodpecker-branded release, version 0.8.104, shipped on September 9, 2019.$q$, $q$Unlike Drone, which is now maintained commercially by Harness under a Polyform Small Business license, Woodpecker CI is maintained by a community of contributors under the Apache 2.0 license and is explicitly committed to staying free and open source, which is its core differentiator against both Drone and hosted CI/CD SaaS products.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Woodpecker maintains backward compatibility with Drone's existing YAML pipeline syntax, so teams migrating from Drone can typically reuse their pipeline configuration files with little modification.$q$, $q$On top of that compatibility, Woodpecker has added its own capabilities, including a modernized web UI, trusted pipeline steps for controlled access to privileged operations, improved conditional step execution, and a growing plugin marketplace for extending pipeline behavior.$q$, $q$Each pipeline step runs inside its own Docker container, and Woodpecker integrates with common Git hosting platforms such as GitHub, GitLab, Gitea and Bitbucket to trigger pipelines automatically on code changes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Woodpecker CI is completely free and open source under the Apache 2.0 license; there is no paid tier, subscription, or commercial license required to use it.$q$, $q$Because it is self-hosted, the only cost to running Woodpecker is the compute infrastructure a team chooses to run it on, giving organizations full control over CI/CD spend compared to per-seat or per-build hosted CI/CD SaaS products.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff195225-a15d-4993-96da-c517414aa5f5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
