-- Enrichment marathon batch: withknown, Wix, Wiz, Wiza, WonderCMS, WooCommerce, Woodpecker, Woodpecker CI

-- ── withknown ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Known is an open-source social publishing platform that lets individuals and groups post blogs, photos, notes and status updates to a self-owned site while syndicating copies out to social networks.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$Small (indie open-source project)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Known (withknown.com) Review: Open-Source Social Publishing Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Known (withknown.com) offers: an open-source, self-hosted social publishing engine for blogs, photos and group sites, built on IndieWeb principles.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Known, published at withknown.com, is an open-source social publishing platform co-founded by Ben Werdmuller and Erin Jo Richey. It was incubated at the Matter Ventures media-startup accelerator in San Francisco and launched publicly on September 11, 2014. Known's core idea is to let a person or a group (a classroom, a research team, a community) run their own collaborative website where multiple authors post short or long-form content -- blog posts, status updates, photos, bookmarks, and other media types -- to one shared, self-owned site, then optionally syndicate copies of that content out to third-party social networks such as Twitter and Facebook. This POSSE-style approach (publish on your own site, syndicate elsewhere) places Known firmly within the IndieWeb movement, which Werdmuller has been involved with since his earlier project, the open-source community platform Elgg. Known is distributed as free, installable open-source software that a user or organization downloads and runs on their own PHP-capable web server, similar in distribution model to WordPress, rather than as a centrally hosted SaaS product with tiered subscription pricing. Documented deployments have included university and media communities such as Harvard, KQED, and Davidson College, with KQED's implementation recognized by a media-literacy award from NAMLE. Functionally, Known supports multiple content types per post (text, photo, checkin, event, and more), a bookmarklet for quick posting from other web pages, hashtag-based organization, custom domains, custom CSS and JavaScript, HTML and WYSIWYG editing, and multiple machine-readable feed formats (RSS, XML, JSON, KML) for interoperability with other tools. Privacy controls allow site owners to run fully public sites, private single-user blogs, or closed group/community discussion spaces. Because Known is self-hosted, there is no vendor lock-in and no recurring platform fee beyond the user's own hosting costs; the tradeoff is that installation, updates, and maintenance are the operator's responsibility rather than a managed service's. As an open-source project driven largely by a small core team and community rather than a large commercial vendor, Known has seen slower feature cadence in recent years compared to hosted competitors like WordPress.com or Ghost, but it remains available, documented, and installable for anyone who wants a lightweight, ownership-first alternative to centralized blogging and social platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ece3f5b6-3302-4069-a41e-b5e480349b71';

