-- ── Wix ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wix is a cloud-based website builder and business platform that lets anyone design, host and manage websites, online stores and web apps using drag-and-drop tools or AI-assisted setup.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$17/month (Light plan, billed annually)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$Large (approximately 4,000-5,500 employees, publicly traded)$q$, company_size),
  headquarters = COALESCE($q$Tel Aviv, Israel$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Portuguese$q$, $q$Italian$q$, $q$Japanese$q$, $q$Hebrew$q$]::text[],
  seo_title = COALESCE($q$Wix Review 2026: Pricing, Features and Website Builder Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Compare Wix pricing plans, features and use cases. See how the drag-and-drop website builder and ecommerce platform from Tel Aviv-based Wix.com works in 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wix is a cloud-based website building and business-management platform founded in 2006 in Tel Aviv, Israel by Avishai Abrahami, Nadav Abrahami and Giora Kaplan. Wix.com Ltd. went public on the NASDAQ (ticker WIX) in November 2013 and today operates as a large, publicly traded software company with offices across Israel, the United States, Europe, Latin America and Asia; reported headcount has ranged roughly between 4,000 and 5,500 employees, with a workforce reduction of about 1,000 roles reported in 2026. Wix's core product lets individuals, freelancers, agencies and small-to-midsize businesses build websites, online stores, blogs, booking systems and web applications without writing code, using a drag-and-drop visual editor (the Wix Editor), a more structured grid-based editor (Editor X / Wix Studio), and AI-assisted site generation tools that create a starting design from a short business description. The platform bundles hosting, a domain, SSL, an app marketplace (Wix App Market), SEO tools, email marketing, and Wix Payments/third-party payment processing under one roof, positioning it as an all-in-one alternative to assembling a website from separate hosting, CMS, and plugin vendors. In 2025 Wix restructured its long-standing plan lineup (which had included Combo, Unlimited, Business Basic, Business Unlimited and Business VIP) into four simplified paid tiers for 2026: Light, Core, Business and Business Elite, priced at $17, $29, $39 and $159 per month respectively on annual billing (higher on month-to-month billing). A free plan remains available but carries Wix branding and ads and lacks ecommerce functionality; the Core plan is the minimum tier required to sell products and accept payments. Beyond the general site builder, Wix operates specialized products including Wix Stores (ecommerce), Wix Bookings (appointment scheduling), Wix Restaurants, Wix Answers (customer support), Velo (a full code development environment for advanced custom logic), and Wix Studio, an editor aimed at agencies and freelance designers building client sites at scale. Wix competes primarily with Squarespace, Shopify (for ecommerce-first use cases), and WordPress-based site builders, and differentiates itself through ease of use, breadth of built-in business tools, and a large template and app ecosystem, while facing recurring criticism around migration lock-in (sites cannot be exported off the Wix platform) and higher costs at scale compared to self-hosted alternatives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2a6940b9-4b57-4612-8541-84535793b340';

