-- ── Wiz ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wiz is a cloud-native application protection platform (CNAPP) that scans AWS, Azure, Google Cloud, Oracle Cloud and Kubernetes environments to find and prioritize security risks across the full cloud stack.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$Large (part of Google Cloud since March 2025/2026, previously 1,000+ employees as an independent company)$q$, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wiz Review: Cloud Security (CNAPP) Platform Now Part of Google Cloud$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn what Wiz (wiz.io) does, its CNAPP platform for AWS, Azure, GCP and Kubernetes security, its founding story, and its acquisition by Google Cloud.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wiz is an Israeli-American cloud security company, headquartered in New York City, that builds a cloud-native application protection platform (CNAPP) used to secure workloads running on Amazon Web Services, Microsoft Azure, Google Cloud Platform, Oracle Cloud Infrastructure, and Kubernetes. The company was founded in January 2020 by Assaf Rappaport, Yinon Costica, Roy Reznik and Ami Luttwak, a team that had previously founded and sold the cloud security company Adallom to Microsoft. Wiz's core technical approach is agentless: rather than requiring software agents installed on every workload, it connects to a customer's cloud accounts via API and builds a full graph of cloud infrastructure, correlating misconfigurations, vulnerabilities, exposed secrets, identity and access risks, and network exposure into prioritized attack-path findings, so security teams can see which combinations of individually low-severity issues actually create a critical, exploitable risk. This unified approach to what had previously been separate tool categories -- cloud security posture management (CSPM), cloud workload protection (CWPP), Kubernetes security posture management (KSPM), data security posture management (DSPM), and cloud infrastructure entitlement management (CIEM) -- is generally credited with popularizing the CNAPP category and driving Wiz's rapid enterprise adoption. Wiz raised capital at a fast pace: a Series B of $250 million at a $1.7 billion valuation in 2021, a Series C of $250 million at a $6 billion valuation later in 2021, a Series D of $300 million at a $10 billion valuation in February 2023, and a Series E of $1 billion at a $12 billion valuation in May 2024, for roughly $1.9 billion in total funding from investors including Insight Partners, Index Ventures, Sequoia, Greenoaks and Lightspeed Venture Partners. On March 18, 2025, Google announced an all-cash agreement to acquire Wiz for approximately 32 billion dollars, a deal described at the time as the largest cybersecurity acquisition ever and the most expensive acquisition in Google's history; the acquisition closed and Wiz became part of Google Cloud in 2026, continuing to operate its platform across multi-cloud environments including AWS and Azure rather than being restricted to Google Cloud only. Wiz is sold to enterprises on a custom, negotiated pricing basis rather than published self-serve tiers, typically scoped to the size of a customer's cloud footprint (workloads, cloud accounts, and modules such as CSPM, CWPP, DSPM, CIEM and container/Kubernetes security). Wiz is important to distinguish from the unrelated website builder Wix (wix.com) and the unrelated LinkedIn prospecting tool Wiza (wiza.co), which share similar names but serve entirely different markets.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e1b75119-d6cf-4ef2-b9ef-c4c9c840eef4';

