-- ── Wiza ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Wiza is a B2B prospecting tool that turns LinkedIn and LinkedIn Sales Navigator searches into verified email addresses and phone numbers for sales, recruiting and marketing outreach.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$49/month per user (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small (roughly 30-40 employees)$q$, company_size),
  headquarters = COALESCE($q$Toronto, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wiza Review 2026: LinkedIn Email Finder Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Wiza (wiza.co) turns LinkedIn Sales Navigator searches into verified emails and phone numbers, plus its 2026 pricing plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wiza is a B2B prospecting and contact-data tool, founded in 2019, that specializes in converting LinkedIn and LinkedIn Sales Navigator searches into exportable, verified lead lists. Its core workflow lets a user run a search inside LinkedIn Sales Navigator (or use Wiza's own search interface), then export the matching profiles through Wiza, which looks up and verifies each contact's business email address and, on higher plans, mobile phone number before the list is downloaded. Wiza markets access to a database described as covering more than 850 million contacts and states it is used by more than 500,000 go-to-market professionals, positioning itself primarily against other LinkedIn-to-email tools and general B2B contact databases. Because emails are verified in real time before export, Wiza aims to reduce the bounce rates that plague lists built from stale, pre-scraped databases. The product is delivered as a web app and as a Chrome extension that integrates directly with the LinkedIn and Sales Navigator interface, and it offers native integrations with common CRMs and sales-engagement tools so exported lists can flow directly into a seller's existing pipeline. Wiza's pricing is credit- and seat-based. A free tier provides a small number of verified emails and phone numbers to try the product. The Starter plan is priced at 49 dollars per month per user and includes a base allotment of verified emails and phone numbers with overage pricing for additional lookups, team analytics and CRM integrations. Two higher self-serve tiers are priced at 83 dollars per month (or 990 dollars billed annually) for unlimited email reveals plus per-phone-number pricing, and 166 dollars per month (or 1,990 dollars billed annually) for unlimited email and phone reveals, both including a monthly export cap, AI-assisted research features, and CRM integrations. A custom-priced Team plan, requiring a minimum of three users and billed annually, adds unlimited email and phone reveals for the whole team, advanced fields, CSV import, API access, and a dedicated customer success manager. Pay-as-you-go, non-subscription pricing is also available at roughly 35 cents per email lookup and 1.50 dollars per phone number lookup for occasional users who do not want a recurring plan. Wiza should not be confused with Wix, the website-building platform, or Wiz, the cloud security company, despite the similarity in name -- all three are unrelated companies serving entirely different markets. Wiza's headquarters location is reported as Toronto, Canada in some company-data sources, with the company operating as a lean, mostly remote team of roughly 30 to 40 employees as of recent reporting.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5118dfca-71e6-4897-bbc7-33e7b849b457';

