-- ── WonderCMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WonderCMS is a free, open-source flat-file content management system built as just five files, requiring no database or complex configuration to run a simple website.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2008, founded_year),
  company_size = COALESCE($q$Small (open-source project maintained by a small community)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WonderCMS Review: Free Flat-File CMS (5 Files, No Database)$q$, seo_title),
  seo_meta_description = COALESCE($q$See how WonderCMS, a free open-source flat-file CMS, lets you run a website from just five files with no database, plus its features, pricing and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WonderCMS is a free, open-source, flat-file content management system designed to be as small and simple as possible: the entire application consists of five files, including a JSON-based text file that serves as the database, meaning it needs no MySQL or other relational database server to operate. The project has existed since 2008 and is licensed under the permissive MIT license, which allows commercial use, modification and redistribution with attribution. Installation is described as a one-step process -- a user unzips and uploads the five files to any PHP-capable web host, and the site is ready to configure through a browser-based admin interface, with no separate database setup, connection strings, or server-side configuration required. Because there is no database layer to query, default WonderCMS installations are reported to score 100 out of 100 on Google PageSpeed tests on both desktop and mobile, making it attractive for users who prioritize raw page-load speed over the plugin-heavy feature depth of larger CMS platforms like WordPress. WonderCMS ships with a theme and plugin installer built into the admin panel, one-click backups and one-click updates, clean and customizable URLs, a built-in file manager, a customizable login URL for security, a configurable homepage, and responsive design out of the box. SEO support is built in as well, letting site owners set a custom title, meta keywords and meta description on a per-page basis without installing a separate SEO plugin. On privacy and security, WonderCMS is positioned as a no-tracking, no-ads, no powered-by-link product that is GDPR compliant by default, and includes full HTTPS support, hashed admin passwords, CSRF protection, single-cookie sessions, and subresource integrity (SRI) checks for its CSS and JavaScript assets. WonderCMS's target audience is developers, freelancers and small businesses who want a minimal-footprint website -- a landing page, a small brochure site, a portfolio, or a simple blog -- without the overhead, attack surface, and maintenance burden of a full database-backed CMS. Its tradeoff versus WordPress or other mainstream CMS platforms is a much smaller plugin and theme ecosystem and fewer built-in features for complex content structures, ecommerce, or multi-author workflows, in exchange for radical simplicity, speed, and a minimal codebase that is easy to audit and self-host.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd7da54f6-2b64-440b-9f41-a831adbd9e11';

