-- ── Woodpecker ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Woodpecker is a cold email and LinkedIn outreach platform that helps sales teams find prospects, run multi-channel outbound campaigns, and manage deliverability and follow-ups in one workflow.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$29/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Medium (approximately 90 employees, publicly traded on the Warsaw Stock Exchange)$q$, company_size),
  headquarters = COALESCE($q$Wroclaw, Poland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Polish$q$]::text[],
  seo_title = COALESCE($q$Woodpecker Review 2026: Cold Email and LinkedIn Outreach Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Woodpecker (woodpecker.co) handles cold email and LinkedIn outreach, its 2026 pricing model, key features, and who it is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Woodpecker is a cold email and LinkedIn outreach platform founded in 2015 in Wroclaw, Poland, built for businesses running outbound sales campaigns. The company has grown into a publicly traded business listed on the Warsaw Stock Exchange under the ticker WPR, employs roughly 90 people, and reports more than 15,000 users across over 100 countries. Woodpecker's product combines prospecting, multi-step cold email campaign sequencing, LinkedIn outreach steps, automated follow-ups, and deliverability tooling (such as email warm-up and inbox rotation) into a single outbound workflow, along with integrations to CRMs and other sales tools so replies and pipeline activity sync with a team's existing systems. The platform's positioning emphasizes deliverability and reply quality over sheer send volume, targeting sales teams, agencies and founders who rely on cold email and LinkedIn as core pipeline-generation channels rather than teams doing high-volume spam-style blasting. Woodpecker's pricing uses a 'contacted prospects' model: rather than charging strictly per seat or per email sent, the price scales with how many new prospects a customer adds to campaigns within a billing cycle, with the base cold-email plan starting at roughly 29 dollars per month for a modest number of contacted prospects and increasing as that ceiling rises. Add-on features are priced separately: LinkedIn automation costs an additional 29 dollars per month per connected LinkedIn account, and certain integrations carry an additional 20 dollars charge. New users can try the platform through a 14-day free trial or a cap of 100 free cold emails, whichever they prefer, before committing to a paid plan. Woodpecker differentiates itself from larger sales-engagement suites like Outreach or Salesloft by focusing specifically on the cold email and LinkedIn outbound use case with a lighter, more accessible interface, making it a common choice for smaller sales teams, founder-led sales, and outbound-focused marketing agencies rather than large enterprise revenue operations teams needing a full CRM-adjacent platform. It should not be confused with the unrelated open-source continuous integration platform Woodpecker CI (woodpecker-ci.org), which shares the Woodpecker name but serves an entirely different developer-tooling market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9716dcf4-3238-4e9c-b8bc-c5a16aa3e250';

