-- ── Woodpecker CI ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Woodpecker CI is a free, open-source continuous integration and delivery engine, community-forked from Drone CI, that runs pipeline steps in Docker containers with a modernized UI and plugin marketplace.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small (community-run open-source project)$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Woodpecker CI Review: Free Open-Source CI/CD (Drone CI Fork)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Woodpecker CI (woodpecker-ci.org) offers: a free, community-run, Apache 2.0 CI/CD engine forked from Drone, with Docker-based pipelines and plugins.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Woodpecker CI is a free, open-source continuous integration and continuous delivery (CI/CD) engine that runs pipeline steps inside Docker containers. It began as a community fork of Drone CI, created after Drone's license changed from the permissive Apache 2.0 license to a proprietary license following its 0.8 release; developer laszlocph forked the last Apache-licensed version of Drone in 2019 to keep a genuinely free and open-source path alive for users who did not want to move to Drone's new commercial license (Drone is now maintained by Harness under a Polyform Small Business license). The first release published under the Woodpecker name was version 0.8.104 on September 9, 2019, and the project has since been maintained and grown by a community of contributors under the woodpecker-ci GitHub organization rather than a single commercial vendor. Woodpecker is licensed under Apache 2.0 and is explicitly positioned as software that will remain free and open source, in direct contrast to Drone's shift toward a paid commercial license -- this is Woodpecker CI's central value proposition and differentiator in the CI/CD space. Architecturally, Woodpecker maintains backward compatibility with Drone's existing YAML pipeline syntax, so teams migrating from Drone can typically reuse their existing pipeline configuration files with minimal changes, while Woodpecker has continued to add its own features on top, including a modernized web UI, trusted/privileged pipeline steps for controlled access to sensitive operations, improved conditional step execution, and an expanding plugin marketplace for extending pipeline functionality. Like Drone, Woodpecker executes each pipeline step inside its own Docker container, giving builds isolated, reproducible environments, and it supports integration with common Git hosting platforms such as GitHub, GitLab, Gitea, Bitbucket and others for triggering pipelines on code changes. Because it is self-hosted and free, Woodpecker CI is typically deployed by teams and organizations that want full control over their CI/CD infrastructure without paying per-seat or per-build SaaS fees, positioning it as an open-source alternative to hosted CI/CD products like CircleCI, GitHub Actions or GitLab CI, as well as a philosophically 'stays free forever' alternative to Drone's now-commercial licensing model. It should not be confused with the unrelated cold email and LinkedIn outreach SaaS tool Woodpecker (woodpecker.co), which shares the Woodpecker name coincidentally but serves an entirely different market.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff195225-a15d-4993-96da-c517414aa5f5';

